import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import API from "../../api/api";

const STATUS_STEPS = ["pending", "in_progress", "completed", "paid"];
const STATUS_COLORS = {
  pending:     "bg-gray-100 text-gray-600",
  in_progress: "bg-blue-100 text-blue-700",
  completed:   "bg-teal-100 text-teal-700",
  paid:        "bg-green-100 text-green-700",
};

const Milestones = () => {
  const { projectId } = useParams();
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user") || "{}");
  const isClient = user.role === "client";

  const [milestones, setMilestones] = useState([]);
  const [loading, setLoading]       = useState(true);
  const [showForm, setShowForm]     = useState(false);
  const [form, setForm]             = useState({ title:"", description:"", amount:"", due_date:"" });
  const [saving, setSaving]         = useState(false);

  useEffect(() => { fetchMilestones(); }, []);

  const fetchMilestones = async () => {
    try {
      const res = await API.get(`/milestones/project/${projectId}`);
      setMilestones(res.data || []);
    } catch(e) {} finally { setLoading(false); }
  };

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleAdd = async () => {
    if (!form.title || !form.amount) return alert("Title and amount are required");
    setSaving(true);
    try {
      const res = await API.post("/milestones", { ...form, project_id: projectId });
      setMilestones(prev => [...prev, {
        id: res.data.id, ...form, status: "pending", created_at: new Date().toISOString()
      }]);
      setForm({ title:"", description:"", amount:"", due_date:"" });
      setShowForm(false);
    } catch(e) { alert("Error saving milestone"); }
    finally { setSaving(false); }
  };

  const updateStatus = async (id, status) => {
    await API.put(`/milestones/${id}/status`, { status });
    setMilestones(prev => prev.map(m => m.id === id ? { ...m, status } : m));
  };

  const deleteMilestone = async (id) => {
    if (!window.confirm("Delete milestone?")) return;
    await API.delete(`/milestones/${id}`);
    setMilestones(prev => prev.filter(m => m.id !== id));
  };

  const totalBudget = milestones.reduce((s, m) => s + Number(m.amount), 0);
  const paidAmount  = milestones.filter(m => m.status === "paid").reduce((s, m) => s + Number(m.amount), 0);
  const progress    = totalBudget > 0 ? Math.round((paidAmount / totalBudget) * 100) : 0;

  const formatDate = (d) => d ? new Date(d).toLocaleDateString("en-IN", { day:"2-digit", month:"short", year:"numeric" }) : "—";

  if (loading) return <div className="text-center py-10 text-gray-500">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-4xl mx-auto">
        <button onClick={() => navigate(-1)} className="text-teal-600 hover:underline text-sm mb-4 block">
          ← Back
        </button>
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold text-gray-800">🎯 Project Milestones</h1>
          {isClient && (
            <button onClick={() => setShowForm(!showForm)}
              className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
              {showForm ? "✕ Cancel" : "+ Add Milestone"}
            </button>
          )}
        </div>

        {/* PROGRESS */}
        {milestones.length > 0 && (
          <div className="bg-white rounded-xl shadow p-5 mb-6">
            <div className="flex justify-between text-sm mb-2">
              <span className="text-gray-600">Payment Progress</span>
              <span className="font-bold text-teal-600">₹{paidAmount.toLocaleString()} / ₹{totalBudget.toLocaleString()}</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-3">
              <div className="bg-teal-600 h-3 rounded-full transition-all duration-500" style={{ width: `${progress}%` }} />
            </div>
            <p className="text-right text-xs text-gray-400 mt-1">{progress}% paid</p>
          </div>
        )}

        {/* ADD FORM */}
        {showForm && isClient && (
          <div className="bg-white rounded-xl shadow p-6 mb-6 border border-teal-100">
            <h2 className="text-lg font-bold text-gray-700 mb-4">Add Milestone</h2>
            <div className="grid grid-cols-1 gap-4">
              <input name="title" value={form.title} onChange={handleChange}
                placeholder="Milestone title *"
                className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500" />
              <textarea name="description" value={form.description} onChange={handleChange} rows={2}
                placeholder="Description (optional)"
                className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500 resize-none" />
              <div className="grid grid-cols-2 gap-4">
                <input name="amount" type="number" value={form.amount} onChange={handleChange}
                  placeholder="Amount (₹) *"
                  className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500" />
                <input name="due_date" type="date" value={form.due_date} onChange={handleChange}
                  className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500" />
              </div>
              <button onClick={handleAdd} disabled={saving}
                className="bg-teal-600 hover:bg-teal-700 text-white py-2 rounded-lg font-medium transition disabled:opacity-50">
                {saving ? "Saving..." : "Add Milestone"}
              </button>
            </div>
          </div>
        )}

        {/* MILESTONES */}
        {milestones.length === 0 ? (
          <div className="bg-white rounded-xl p-12 text-center text-gray-400 shadow">
            <div className="text-5xl mb-3">🎯</div>
            <p>No milestones yet.{isClient ? " Add one to track payments!" : ""}</p>
          </div>
        ) : (
          <div className="space-y-4">
            {milestones.map((m, i) => (
              <div key={m.id} className="bg-white rounded-xl shadow p-5 border border-gray-100">
                <div className="flex justify-between items-start">
                  <div className="flex items-start gap-3">
                    <div className="w-8 h-8 bg-teal-100 text-teal-700 rounded-full flex items-center justify-center font-bold text-sm flex-shrink-0">
                      {i + 1}
                    </div>
                    <div>
                      <h3 className="font-bold text-gray-800">{m.title}</h3>
                      {m.description && <p className="text-gray-500 text-sm mt-0.5">{m.description}</p>}
                      <div className="flex gap-4 mt-2 text-sm text-gray-500">
                        <span className="font-bold text-teal-600">₹{Number(m.amount).toLocaleString()}</span>
                        {m.due_date && <span>Due: {formatDate(m.due_date)}</span>}
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`px-3 py-1 rounded-full text-xs font-semibold capitalize ${STATUS_COLORS[m.status]}`}>
                      {m.status?.replace("_", " ")}
                    </span>
                    {isClient && (
                      <button onClick={() => deleteMilestone(m.id)}
                        className="text-red-400 hover:text-red-600 transition text-lg">🗑</button>
                    )}
                  </div>
                </div>

                {/* Status progression buttons */}
                <div className="flex gap-2 mt-4 flex-wrap">
                  {STATUS_STEPS.map((step) => {
                    const currentIdx = STATUS_STEPS.indexOf(m.status);
                    const stepIdx    = STATUS_STEPS.indexOf(step);
                    const isNext     = stepIdx === currentIdx + 1;
                    const isDone     = stepIdx <= currentIdx;
                    if (!isClient && step !== "completed") return null;
                    return (
                      <button key={step}
                        onClick={() => isNext && updateStatus(m.id, step)}
                        disabled={!isNext}
                        className={`px-3 py-1 rounded-lg text-xs font-medium transition capitalize ${
                          isDone    ? "bg-teal-600 text-white cursor-default" :
                          isNext    ? "bg-teal-50 text-teal-700 hover:bg-teal-100 border border-teal-300" :
                                      "bg-gray-100 text-gray-400 cursor-not-allowed"
                        }`}>
                        {isDone ? "✓ " : ""}{step.replace("_", " ")}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Milestones;
